#ifndef FUSED_ADD_RMSNORM_H7168_KERNEL_H_
#define FUSED_ADD_RMSNORM_H7168_KERNEL_H_

#include <cuda_runtime.h>
#include <cuda_bf16.h>
#include <stdint.h>

static constexpr int kHiddenSize7168 = 7168;

// Copy weight to device constant memory on the provided stream.
void fused_add_rmsnorm_h7168_set_weight_const(const __nv_bfloat16* weight_ptr_device,
                                             cudaStream_t stream);

// Launch kernel:
// output[b, j] = ( (hs[b,j] + residual[b,j]) * rsqrt(mean((hs+res)^2)+eps) ) * weight[j]
void fused_add_rmsnorm_h7168_launch(const __nv_bfloat16* hidden_states,  // [B,7168]
                                    const __nv_bfloat16* residual,       // [B,7168]
                                    const __nv_bfloat16* weight,         // [7168] (fallback if const disabled)
                                    __nv_bfloat16* output,               // [B,7168]
                                    int64_t batch_size,
                                    cudaStream_t stream);

#endif  // FUSED_ADD_RMSNORM_H7168_KERNEL_H_

#include "kernel.h"

#include <cuda.h>
#include <cuda_runtime.h>
#include <cuda_bf16.h>
#include <stdint.h>

#if defined(__CUDA_ARCH__)
#if __CUDA_ARCH__ < 800
#error "Requires sm80+ (Ampere/A800)."
#endif
#endif

#define CUDA_CHECK_THROW(expr) do {                                     \
  cudaError_t _e = (expr);                                              \
  if (_e != cudaSuccess) {                                              \
    printf("CUDA error %s at %s:%d\n", cudaGetErrorString(_e), __FILE__, __LINE__); \
  }                                                                     \
} while (0)

__device__ __constant__ __nv_bfloat16 c_weight_7168[kHiddenSize7168];

void fused_add_rmsnorm_h7168_set_weight_const(const __nv_bfloat16* weight_ptr_device,
                                             cudaStream_t stream) {
  if (!weight_ptr_device) return;
  CUDA_CHECK_THROW(cudaMemcpyToSymbolAsync(
      c_weight_7168,
      weight_ptr_device,
      kHiddenSize7168 * sizeof(__nv_bfloat16),
      0,
      cudaMemcpyDeviceToDevice,
      stream));
}

static __device__ __forceinline__ float warp_sum(float v) {
#pragma unroll
  for (int offset = 16; offset > 0; offset >>= 1) {
    v += __shfl_down_sync(0xffffffff, v, offset);
  }
  return v;
}

// blockDim.x must be 256
static __device__ __forceinline__ float block_sum_256(float v) {
  __shared__ float warp_sums[8]; // 256/32 = 8 warps
  const int lane = threadIdx.x & 31;
  const int warp = threadIdx.x >> 5;

  v = warp_sum(v);
  if (lane == 0) warp_sums[warp] = v;
  __syncthreads();

  float out = 0.0f;
  if (warp == 0) {
    out = (lane < 8) ? warp_sums[lane] : 0.0f;
    out = warp_sum(out);
  }
  return out; // valid in all threads; non-warp0 threads get 0 but we broadcast via shared below
}

__global__ void fused_add_rmsnorm_h7168_kernel(const __nv_bfloat16* __restrict__ hidden_states,
                                               const __nv_bfloat16* __restrict__ residual,
                                               const __nv_bfloat16* __restrict__ weight_gmem,
                                               __nv_bfloat16* __restrict__ output,
                                               int64_t batch_size,
                                               int use_const_weight) {
  const int row = (int)blockIdx.x;
  if ((int64_t)row >= batch_size) return;

  constexpr int H = kHiddenSize7168;
  constexpr int H2 = H / 2;
  constexpr float EPS = 1e-6f;

  const int tid = threadIdx.x;
  const int base = row * H;

  const __nv_bfloat16* w_ptr = use_const_weight ? c_weight_7168 : weight_gmem;

  // Use vectorized path only when base pointers are 4-byte aligned.
  const uintptr_t hs_addr  = (uintptr_t)(hidden_states + base);
  const uintptr_t rs_addr  = (uintptr_t)(residual + base);
  const uintptr_t out_addr = (uintptr_t)(output + base);
  const uintptr_t w_addr   = (uintptr_t)(w_ptr);
  const bool vec_ok = ((hs_addr | rs_addr | out_addr | w_addr) & 0x3u) == 0;

  float sum_local = 0.0f;

  if (vec_ok) {
    const __nv_bfloat162* hs2 = reinterpret_cast<const __nv_bfloat162*>(hidden_states + base);
    const __nv_bfloat162* rs2 = reinterpret_cast<const __nv_bfloat162*>(residual + base);

#pragma unroll 4
    for (int j2 = tid; j2 < H2; j2 += 256) {
      const float2 a = __bfloat1622float2(hs2[j2]);
      const float2 b = __bfloat1622float2(rs2[j2]);
      const float x0 = a.x + b.x;
      const float x1 = a.y + b.y;
      sum_local = fmaf(x0, x0, sum_local);
      sum_local = fmaf(x1, x1, sum_local);
    }
  } else {
#pragma unroll 4
    for (int j = tid; j < H; j += 256) {
      const float x = __bfloat162float(hidden_states[base + j]) +
                      __bfloat162float(residual[base + j]);
      sum_local = fmaf(x, x, sum_local);
    }
  }

  const float sumsq_warp0 = block_sum_256(sum_local);

  __shared__ float inv_rms_sh;
  if (tid == 0) {
    const float mean = sumsq_warp0 * (1.0f / (float)H);
    inv_rms_sh = rsqrtf(mean + EPS);
  }
  __syncthreads();
  const float inv_rms = inv_rms_sh;

  if (vec_ok) {
    const __nv_bfloat162* hs2 = reinterpret_cast<const __nv_bfloat162*>(hidden_states + base);
    const __nv_bfloat162* rs2 = reinterpret_cast<const __nv_bfloat162*>(residual + base);
    const __nv_bfloat162* w2  = reinterpret_cast<const __nv_bfloat162*>(w_ptr);
    __nv_bfloat162* out2      = reinterpret_cast<__nv_bfloat162*>(output + base);

#pragma unroll 4
    for (int j2 = tid; j2 < H2; j2 += 256) {
      const float2 a = __bfloat1622float2(hs2[j2]);
      const float2 b = __bfloat1622float2(rs2[j2]);
      const float2 w = __bfloat1622float2(w2[j2]);
      const float x0 = a.x + b.x;
      const float x1 = a.y + b.y;
      const float y0 = (x0 * inv_rms) * w.x;
      const float y1 = (x1 * inv_rms) * w.y;
      out2[j2] = __floats2bfloat162_rn(y0, y1);
    }
  } else {
#pragma unroll 4
    for (int j = tid; j < H; j += 256) {
      const float x = __bfloat162float(hidden_states[base + j]) +
                      __bfloat162float(residual[base + j]);
      const float w = __bfloat162float(w_ptr[j]);
      output[base + j] = __float2bfloat16_rn((x * inv_rms) * w);
    }
  }
}

void fused_add_rmsnorm_h7168_launch(const __nv_bfloat16* hidden_states,
                                   const __nv_bfloat16* residual,
                                   const __nv_bfloat16* weight,
                                   __nv_bfloat16* output,
                                   int64_t batch_size,
                                   cudaStream_t stream) {
  if (batch_size <= 0) return;

  dim3 block(256, 1, 1);
  dim3 grid((unsigned)batch_size, 1, 1);

  // Constant memory is used only after set_weight_const was called.
  const int use_const = 1;

  fused_add_rmsnorm_h7168_kernel<<<grid, block, 0, stream>>>(
      hidden_states, residual, weight, output, batch_size, use_const);
}

#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>

#include <cuda_runtime.h>
#include <sstream>
#include <stdexcept>

#include "kernel.h"

static void check_cuda_bf16_contig(const torch::Tensor& t, const char* name) {
  if (!t.defined()) {
    std::ostringstream oss; oss << name << " is undefined";
    throw std::invalid_argument(oss.str());
  }
  if (!t.device().is_cuda()) {
    std::ostringstream oss; oss << name << " must be a CUDA tensor";
    throw std::invalid_argument(oss.str());
  }
  if (t.dtype() != torch::kBFloat16) {
    std::ostringstream oss; oss << name << " must have dtype torch.bfloat16";
    throw std::invalid_argument(oss.str());
  }
  if (!t.is_contiguous()) {
    std::ostringstream oss; oss << name << " must be contiguous";
    throw std::invalid_argument(oss.str());
  }
}

static void check_shape(const torch::Tensor& hidden_states,
                        const torch::Tensor& residual,
                        const torch::Tensor& weight) {
  if (hidden_states.dim() != 2) {
    throw std::invalid_argument("hidden_states must have shape [batch_size, hidden_size]");
  }
  if (residual.dim() != 2) {
    throw std::invalid_argument("residual must have shape [batch_size, hidden_size]");
  }
  if (weight.dim() != 1) {
    throw std::invalid_argument("weight must have shape [hidden_size]");
  }

  const int64_t batch_size = hidden_states.size(0);
  const int64_t hidden_size = hidden_states.size(1);

  if (batch_size < 0) throw std::invalid_argument("batch_size must be >= 0");
  if (hidden_size != kHiddenSize7168) {
    throw std::invalid_argument("hidden_size must be 7168");
  }
  if (residual.size(0) != batch_size || residual.size(1) != hidden_size) {
    throw std::invalid_argument("residual shape must match hidden_states shape");
  }
  if (weight.size(0) != hidden_size) {
    throw std::invalid_argument("weight shape must be [7168]");
  }
  if (residual.device() != hidden_states.device() || weight.device() != hidden_states.device()) {
    throw std::invalid_argument("All inputs must be on the same CUDA device");
  }
}

torch::Tensor run(torch::Tensor hidden_states,
                  torch::Tensor residual,
                  torch::Tensor weight) {
  check_cuda_bf16_contig(hidden_states, "hidden_states");
  check_cuda_bf16_contig(residual, "residual");
  check_cuda_bf16_contig(weight, "weight");
  check_shape(hidden_states, residual, weight);

  const int64_t batch_size = hidden_states.size(0);
  auto output = torch::empty_like(hidden_states);

  const __nv_bfloat16* hs_ptr =
      reinterpret_cast<const __nv_bfloat16*>(hidden_states.data_ptr<at::BFloat16>());
  const __nv_bfloat16* rs_ptr =
      reinterpret_cast<const __nv_bfloat16*>(residual.data_ptr<at::BFloat16>());
  const __nv_bfloat16* w_ptr =
      reinterpret_cast<const __nv_bfloat16*>(weight.data_ptr<at::BFloat16>());
  __nv_bfloat16* out_ptr =
      reinterpret_cast<__nv_bfloat16*>(output.data_ptr<at::BFloat16>());

  // Correct stream: use current PyTorch stream.
  cudaStream_t stream = at::cuda::getDefaultCUDAStream(hidden_states.device().index());
  stream = at::cuda::getCurrentCUDAStream(hidden_states.device().index()).stream();

  // Update constant memory weight on the same stream to preserve ordering.
  fused_add_rmsnorm_h7168_set_weight_const(w_ptr, stream);
  fused_add_rmsnorm_h7168_launch(hs_ptr, rs_ptr, w_ptr, out_ptr, batch_size, stream);

  // Make launch failures visible to PyTorch.
  cudaError_t err = cudaGetLastError();
  if (err != cudaSuccess) {
    std::ostringstream oss;
    oss << "CUDA launch failed: " << cudaGetErrorString(err);
    throw std::runtime_error(oss.str());
  }

  return output;
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
  m.def("run", &run, "Kernel execution function (fused_add_rmsnorm_h7168)",
        py::arg("hidden_states"), py::arg("residual"), py::arg("weight"));
}
